export type GeoWpLocale = 'it' | 'en';

export const GEO_WP_CSS = "\n  /* ============================================================\n     EDITORIAL SWISS / INTERNATIONAL TYPOGRAPHIC STYLE\n     - griglia rigorosa, allineamento a sinistra, asimmetria\n     - regole hairline nere, zero border-radius, zero ombre morbide\n     - rosso svizzero come unico accento, usato come segnale di dato\n     - Funnel Display (titoli) + Funnel Sans (testo)\n     ============================================================ */\n  :root{\n    --paper:#f7f6f3;\n    --ink:#111111;\n    --ink-2:#3a3a3a;\n    --ink-3:#6f6f6f;\n    --rule:#111111;\n    --rule-soft:#cdccc7;\n    --red:#f57f44;          /* accento - segnale dato */\n    --blue:#1b4dc1;         /* dato dense/semantico */\n    --green:#1e7a3d;\n    --amber:#b06a00;\n    --grid-gap:24px;\n  }\n  *{box-sizing:border-box}\n  html{scroll-behavior:smooth}\n  body{\n    margin:0;background:var(--paper);color:var(--ink);\n    font-family:var(--font-sans),system-ui,sans-serif;\n    font-size:18px;line-height:1.55;font-weight:400;\n    -webkit-font-smoothing:antialiased;\n  }\n  @media(prefers-reduced-motion:reduce){*{animation:none!important;transition:none!important}}\n\n  .wrap{max-width:1180px;margin:0 auto;padding:0 32px}\n  @media(max-width:640px){.wrap{padding:0 20px}}\n\n  /* ---------- type scale ---------- */\n  h1,h2,h3,h4,h5{font-family:var(--font-display),sans-serif;font-weight:700;letter-spacing:-.02em;line-height:1.02;margin:0}\n  .display{font-size:clamp(48px,10vw,124px);font-weight:800;letter-spacing:-.04em;line-height:.92}\n  h2{font-size:clamp(28px,4.5vw,46px);font-weight:700;letter-spacing:-.03em;line-height:1.0}\n  h3{font-size:clamp(20px,2.6vw,26px);font-weight:600;letter-spacing:-.02em;margin-top:34px}\n  h4{font-family:var(--font-sans),sans-serif;font-size:12px;font-weight:700;letter-spacing:.14em;\n     text-transform:uppercase;color:var(--ink);margin-top:28px;margin-bottom:2px}\n  p{margin:0 0 16px;max-width:68ch}\n  .lede{font-size:clamp(20px,2.6vw,27px);line-height:1.32;font-weight:400;letter-spacing:-.01em;max-width:30ch}\n  a{color:var(--ink);text-decoration:underline;text-decoration-thickness:1px;text-underline-offset:2px}\n  strong{font-weight:700}\n  em{font-style:italic}\n  code{font-family:var(--font-sans),monospace;font-size:.85em;background:#ececE8;padding:1px 5px;border:1px solid var(--rule-soft)}\n  ul,ol{margin:0 0 18px;padding-left:0;list-style:none;max-width:68ch}\n  ul li,ol li{position:relative;padding-left:26px;margin-bottom:10px}\n  ul li::before{content:\"\";position:absolute;left:0;top:11px;width:10px;height:1.5px;background:var(--ink)}\n  ol{counter-reset:o}\n  ol li{counter-increment:o}\n  ol li::before{content:counter(o);position:absolute;left:0;top:0;font-family:var(--font-display);font-weight:700;font-size:13px;color:var(--red)}\n\n  .mono{font-family:var(--font-sans),sans-serif;font-variant-numeric:tabular-nums}\n  .kicker{font-size:12px;font-weight:700;letter-spacing:.18em;text-transform:uppercase}\n  .red{color:var(--red)}\n\n  /* ---------- masthead ---------- */\n  .masthead{border-bottom:3px solid var(--ink)}\n  .masthead .wrap{padding:18px 32px}\n  .mast-top{display:flex;justify-content:space-between;align-items:baseline;\n    border-bottom:1px solid var(--ink);padding-bottom:10px;margin-bottom:42px;\n    font-size:12px;font-weight:700;letter-spacing:.14em;text-transform:uppercase}\n  .mast-top .r{color:var(--red)}\n  .hero-grid{display:grid;grid-template-columns:1fr 1fr;gap:var(--grid-gap);align-items:end;padding-bottom:34px}\n  @media(max-width:780px){.hero-grid{grid-template-columns:1fr;gap:16px}}\n  .hero-sub{border-top:2px solid var(--ink);padding-top:14px}\n  .byline{font-size:13px;color:var(--ink-3);line-height:1.6;margin-top:18px}\n  .byline a{color:var(--red)}\n  .meta-row{display:flex;gap:24px;flex-wrap:wrap;margin-top:14px;\n    font-size:11px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--ink-2)}\n  .meta-row span{border-left:2px solid var(--red);padding-left:8px}\n\n  /* ---------- section scaffolding ---------- */\n  main .wrap{padding-top:0}\n  section{padding:48px 0;border-bottom:1px solid var(--rule-soft)}\n  .sec-grid{display:grid;grid-template-columns:140px 1fr;gap:var(--grid-gap)}\n  @media(max-width:780px){.sec-grid{grid-template-columns:1fr;gap:10px}}\n  .sec-aside{position:relative}\n  .sec-aside .num{font-family:var(--font-display);font-weight:800;font-size:13px;color:var(--red);letter-spacing:.1em}\n  .sec-aside .lbl{font-size:11px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:var(--ink-3);margin-top:6px;display:block}\n  @media(min-width:781px){.sec-aside{position:sticky;top:24px;height:max-content}}\n  .sec-body h2{margin-bottom:20px}\n\n  /* ---------- key list ---------- */\n  .keylist{counter-reset:k;max-width:none}\n  .keylist li{padding-left:0;margin-bottom:0;border-top:1px solid var(--ink);padding-top:14px;padding-bottom:14px;\n    display:grid;grid-template-columns:46px 1fr;gap:14px;counter-increment:k}\n  .keylist li::before{content:counter(k,decimal-leading-zero);position:static;width:auto;height:auto;background:none;\n    font-family:var(--font-display);font-weight:800;font-size:20px;color:var(--red);top:auto;left:auto}\n  .keylist li:last-child{border-bottom:1px solid var(--ink)}\n\n  /* ---------- tables ---------- */\n  .tablewrap{overflow-x:auto;margin:22px 0;border-top:2px solid var(--ink);border-bottom:2px solid var(--ink)}\n  table{border-collapse:collapse;width:100%;font-size:14px}\n  th,td{text-align:left;padding:9px 14px 9px 0;border-bottom:1px solid var(--rule-soft);vertical-align:top}\n  th{font-size:11px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;border-bottom:1px solid var(--ink)}\n  tr:last-child td{border-bottom:none}\n\n  /* ---------- callout panels ---------- */\n  .panel{border:2px solid var(--ink);padding:20px 22px;margin:24px 0}\n  .panel h4{margin-top:0}\n  blockquote{margin:22px 0;padding:0 0 0 20px;border-left:3px solid var(--red);\n    font-family:var(--font-display);font-weight:500;font-size:22px;line-height:1.2;letter-spacing:-.02em;max-width:40ch}\n  .note{border:1px solid var(--ink);border-left:6px solid var(--ink);padding:14px 16px;margin:18px 0;\n    font-size:13.5px;line-height:1.5;color:var(--ink-2);background:#efeeea}\n  .note strong{color:var(--ink)}\n\n  /* badges */\n  .badge{font-size:11px;font-weight:700;letter-spacing:.04em;padding:2px 7px;white-space:nowrap;display:inline-block;border:1.5px solid}\n  .b-ok{color:var(--green);border-color:var(--green)}\n  .b-warn{color:var(--amber);border-color:var(--amber)}\n  .b-bad{color:var(--red);border-color:var(--red)}\n\n  /* ============ DEMOS ============ */\n  .demo{border:2.5px solid var(--ink);margin:34px 0;background:var(--paper)}\n  .demo-head{background:var(--ink);color:var(--paper);padding:12px 18px;display:flex;align-items:center;gap:12px;\n    font-size:12px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;font-family:var(--font-display)}\n  .demo-head .dot{width:9px;height:9px;background:var(--red);border-radius:0;animation:blink 1.6s steps(1) infinite}\n  @keyframes blink{50%{opacity:.25}}\n  .demo-head .tag{margin-left:auto;color:#d8d8d8;font-weight:500;letter-spacing:.08em;font-size:10.5px;text-transform:none;font-family:var(--font-sans)}\n  .demo-body{padding:22px 18px}\n  .demo-cap{padding:0 18px 16px;font-size:12.5px;line-height:1.5;color:var(--ink-3);border-top:1px solid var(--rule-soft);padding-top:12px;margin:0 18px 14px}\n  .demo label{font-size:11px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--ink-2);display:block;margin-bottom:6px}\n  .demo input[type=text]{width:100%;font-family:var(--font-sans);font-size:15px;padding:11px 12px;border:1.5px solid var(--ink);background:#fff;color:var(--ink)}\n  .demo input[type=text]:focus{outline:3px solid var(--red);outline-offset:-1px}\n  .demo input[type=range]{width:100%;accent-color:var(--red);margin:10px 0}\n  .demo button{font-family:var(--font-display);font-size:13px;font-weight:600;padding:10px 18px;border:1.5px solid var(--ink);\n    background:var(--ink);color:var(--paper);cursor:pointer;transition:background .12s}\n  .demo button:hover{background:var(--red);border-color:var(--red)}\n  .demo button.ghost{background:transparent;color:var(--ink)}\n  .demo button.ghost:hover{background:var(--ink);color:var(--paper)}\n  .chips{display:flex;flex-wrap:wrap;gap:8px;margin-top:10px}\n  .chip{font-size:11.5px;font-weight:600;padding:6px 11px;border:1.5px solid var(--ink);background:transparent;cursor:pointer}\n  .chip:hover{background:var(--ink);color:var(--paper)}\n\n  .fan-out{margin-top:18px;display:none}\n  .fan-q{font-size:14px;padding:9px 13px;margin:7px 0;border:1.5px solid var(--ink);border-left:5px solid var(--red);\n    opacity:0;transform:translateX(-10px);animation:slidein .38s forwards}\n  @keyframes slidein{to{opacity:1;transform:translateX(0)}}\n  .fan-q .lbl{font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--red);display:block;margin-bottom:3px}\n\n  .chunk-controls{display:flex;gap:0;flex-wrap:wrap;margin:16px 0;border:1.5px solid var(--ink);width:max-content;max-width:100%}\n  .chunk-controls button{border:none;border-right:1.5px solid var(--ink)}\n  .chunk-controls button:last-child{border-right:none}\n  .chunk-out{margin-top:16px;display:flex;flex-direction:column;gap:0;border-top:1.5px solid var(--ink)}\n  .chunk{padding:10px 12px;font-size:14px;line-height:1.4;border-bottom:1.5px solid var(--ink);position:relative;animation:fadein .3s}\n  @keyframes fadein{from{opacity:0}to{opacity:1}}\n  .chunk .tag{font-family:var(--font-display);font-size:10px;font-weight:700;letter-spacing:.06em;color:var(--red);display:block;margin-bottom:3px}\n  .chunk.c0{background:rgba(27,77,193,.06)} .chunk.c1{background:rgba(245,127,68,.10)} .chunk.c2{background:rgba(30,122,61,.06)}\n  .chunk-meta{font-size:12px;color:var(--ink-3);margin-top:12px;line-height:1.5}\n\n  .ds-grid{display:grid;grid-template-columns:1fr 1fr;margin-top:18px;border:1.5px solid var(--ink)}\n  @media(max-width:560px){.ds-grid{grid-template-columns:1fr}}\n  .ds-col{padding:16px}\n  .ds-col.dense{border-right:1.5px solid var(--ink)}\n  @media(max-width:560px){.ds-col.dense{border-right:none;border-bottom:1.5px solid var(--ink)}}\n  .ds-col h5{font-family:var(--font-display);font-size:12px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;margin-bottom:6px}\n  .ds-col.dense h5{color:var(--blue)} .ds-col.sparse h5{color:var(--red)}\n  .ds-score{font-family:var(--font-display);font-size:42px;font-weight:800;line-height:1;letter-spacing:-.03em}\n  .ds-col.dense .ds-score{color:var(--blue)} .ds-col.sparse .ds-score{color:var(--red)}\n  .ds-bar{height:8px;background:#e0dfda;overflow:hidden;margin:10px 0}\n  .ds-bar span{display:block;height:100%;width:0;transition:width .6s cubic-bezier(.2,.7,.2,1)}\n  .ds-col.dense .ds-bar span{background:var(--blue)} .ds-col.sparse .ds-bar span{background:var(--red)}\n  .ds-note{font-size:12px;color:var(--ink-2);margin-top:8px;line-height:1.4}\n\n  .se-readout{display:flex;gap:28px;align-items:flex-end;margin:16px 0;flex-wrap:wrap}\n  .se-big{font-family:var(--font-display);font-size:56px;font-weight:800;line-height:.9;color:var(--red);letter-spacing:-.04em}\n  .se-big small{display:block;font-family:var(--font-sans);font-size:11px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--ink-3);margin-top:6px}\n  .se-runs{font-size:13px;font-weight:600;color:var(--ink-2)}\n  .se-track{position:relative;height:60px;margin:18px 0 10px;border:1.5px solid var(--ink);background:#fff;overflow:hidden}\n  .se-true{position:absolute;top:0;bottom:0;left:50%;width:2px;background:var(--ink);z-index:3}\n  .se-true::after{content:\"valore reale 50%\";position:absolute;top:5px;left:6px;font-size:9.5px;font-weight:700;letter-spacing:.06em;text-transform:uppercase;white-space:nowrap}\n  .se-ci{position:absolute;top:50%;transform:translateY(-50%);height:24px;background:rgba(245,127,68,.20);border:1.5px solid var(--red);transition:left .4s,width .4s;z-index:2}\n  .se-verdict{font-size:12.5px;font-weight:600;padding:10px 13px;margin-top:8px;line-height:1.5;border:1.5px solid}\n  .se-verdict.bad{border-color:var(--red);color:var(--red)}\n  .se-verdict.warn{border-color:var(--amber);color:var(--amber)}\n  .se-verdict.ok{border-color:var(--green);color:var(--green)}\n\n  /* progress + toc */\n  .progress{position:fixed;top:0;left:0;height:4px;background:var(--red);width:0;z-index:50}\n  .toc-toggle{position:fixed;right:20px;bottom:20px;z-index:40;font-family:var(--font-display);font-size:12px;font-weight:600;\n    letter-spacing:.06em;background:var(--ink);color:var(--paper);border:none;padding:12px 18px;cursor:pointer}\n  .toc{position:fixed;right:20px;bottom:62px;z-index:40;background:var(--paper);border:2.5px solid var(--ink);\n    padding:8px 0;max-width:300px;display:none}\n  .toc.open{display:block}\n  .toc a{display:block;font-size:12.5px;font-weight:600;color:var(--ink);text-decoration:none;padding:8px 18px;border-bottom:1px solid var(--rule-soft)}\n  .toc a:hover{background:var(--ink);color:var(--paper)}\n  .toc a:last-child{border-bottom:none}\n\n  /* footer / biblio */\n  footer{border-top:3px solid var(--ink);background:var(--ink);color:var(--paper)}\n  footer .wrap{padding:40px 32px}\n  footer h2{color:var(--paper)}\n  footer a{color:#f9a87a}\n  .biblio{columns:2;column-gap:40px;font-size:12.5px;line-height:1.45}\n  @media(max-width:640px){.biblio{columns:1}}\n  .biblio h4{color:#f9a87a;break-after:avoid;margin-top:18px}\n  .biblio ul{max-width:none}\n  .biblio li{color:#cfcfcf;break-inside:avoid;padding-left:14px}\n  .biblio li::before{background:var(--red);top:9px}\n  .foot-meta{border-top:1px solid #444;margin-top:28px;padding-top:18px;font-size:12px;color:#9a9a9a;line-height:1.6}\n";

export const GEO_WP_BODY: Record<GeoWpLocale, string> = {
  it: "<header class=\"masthead\">\n  <div class=\"wrap\">\n    <div class=\"mast-top\"><span>White Paper</span><span>Generative Engine Optimization</span><span class=\"r\">2026</span></div>\n    <div class=\"hero-grid\">\n      <div>\n        <h1 class=\"display\">SEO<br>→ <span class=\"red\">GEO</span></h1>\n      </div>\n      <div class=\"hero-sub\">\n        <p class=\"lede\">L'evoluzione della ricerca nell'era dell'AI generativa.</p>\n        <div class=\"byline\">\n          A cura di <a href=\"https://github.com/federicokalik\">Federico Calicchia</a> · redatto con il supporto di Claude Opus 4.8 (Anthropic) su indicazioni editoriali.\n        </div>\n        <div class=\"meta-row\"><span>Ultimo aggiornamento · 16 giugno 2026</span></div>\n      </div>\n    </div>\n  </div>\n</header>\n\n<main>\n<div class=\"wrap\">\n\n<!-- INTRO -->\n<section id=\"intro\">\n  <div class=\"sec-grid\">\n    <div class=\"sec-aside\"><span class=\"num\">00</span><span class=\"lbl\">Introduzione</span></div>\n    <div class=\"sec-body\">\n      <p class=\"lede\" style=\"margin-bottom:24px\">Per vent'anni la ricerca ha avuto una grammatica stabile: query → lista di link → click. Quella grammatica si sta rompendo.</p>\n      <p>Su quella meccanica — crawling, indexing, ranking, click-through — si è costruita un'intera disciplina, la SEO, e con essa il modello economico del web aperto. I motori generativi (Google con AI Overviews e AI Mode, ChatGPT, Perplexity, Microsoft Copilot, Claude) non restituiscono più primariamente una lista di link: leggono il web al posto dell'utente, sintetizzano una risposta e citano poche fonti. Il click, che era il fine, diventa l'eccezione.</p>\n      <p>Cambia l'unità di competizione (non più la pagina ma il singolo <em>chunk</em> citabile), cambiano le metriche (dalla posizione in SERP alla quota di citazione), cambiano gli attori (un arcipelago frammentato, anche fuori dall'Occidente). Da qui nasce la GEO, <em>Generative Engine Optimization</em>.</p>\n      <p>Questo documento ha tre obiettivi: spiegare <strong>come funzionano davvero</strong> i motori a livello di retrieval e selezione fonti; <strong>distinguere ciò che è documentato</strong> da ciò che è inferito o solo affermato dai vendor; <strong>collocare il fenomeno nel contesto italiano ed europeo</strong>. Taglio formativo e analitico: capire il meccanismo, non vendere una ricetta.</p>\n    </div>\n  </div>\n</section>\n\n<!-- TLDR -->\n<section id=\"tldr\">\n  <div class=\"sec-grid\">\n    <div class=\"sec-aside\"><span class=\"num\">—</span><span class=\"lbl\">In breve</span></div>\n    <div class=\"sec-body\">\n      <h2>Cinque punti</h2>\n      <ul class=\"keylist\">\n        <li><div>Lo zero-click è strutturale: nel 2024 il 58,5% delle ricerche Google USA finiva senza click (SparkToro/Datos), salito al <strong>68,01%</strong> a inizio 2026. Con un AI Overview il CTR organico della pagina top cala del <strong>47-61%</strong> a seconda dello studio.</div></li>\n        <li><div>La GEO nasce dal paper di Aggarwal et al. (KDD 2024): statistiche, citazioni e quotazioni alzano la visibilità <strong>\"fino al 40%\"</strong>; il keyword stuffing è l'unico metodo testato che la <em>peggiora</em>.</div></li>\n        <li><div>Ogni motore ha una pipeline diversa (ChatGPT su Bing/scraping, Perplexity con crawler proprio, Claude su Brave, Copilot su Bing/Prometheus, Gemini con fan-out): tutti usano RAG, embeddings e selezione a livello di chunk.</div></li>\n        <li><div>La visibilità AI è una distribuzione, non un punteggio: una misura singola ha errore standard <strong>0,370</strong> (inutile); servono 7-10+ run per prompt (paper \"Don't Measure Once\").</div></li>\n        <li><div>Google stessa (maggio 2026) dichiara che <strong>\"GEO è ancora SEO\"</strong> e smonta 5 miti, tra cui llms.txt e il chunking manuale.</div></li>\n      </ul>\n    </div>\n  </div>\n</section>\n\n<!-- SEC 1 -->\n<section id=\"s1\">\n  <div class=\"sec-grid\">\n    <div class=\"sec-aside\"><span class=\"num\">01</span><span class=\"lbl\">Fondamenti</span></div>\n    <div class=\"sec-body\">\n      <h2>L'evoluzione dalla SEO alla GEO</h2>\n      <h4>Ricerca tradizionale</h4>\n      <p>La SEO classica si basa su tre fasi: <strong>crawling</strong> (un bot scopre e scarica pagine), <strong>indexing</strong> (archiviazione in un indice), <strong>ranking</strong> (ordinamento che produce la SERP). Il modello economico era il <strong>click-through</strong>.</p>\n      <h4>Ricerca AI-driven</h4>\n      <p>I motori generativi <strong>sintetizzano una risposta</strong> da più fonti con un LLM, citandone alcune inline → risposte <strong>zero-click</strong>. Google ha integrato il paradigma con AI Overviews (riquadri in cima alla SERP) e AI Mode (esperienza conversazionale).</p>\n      <h4>Timeline dei punti di svolta</h4>\n      <ul>\n        <li>Mag 2023: Google annuncia SGE in Search Labs.</li>\n        <li>14 mag 2024: AI Overviews lanciati negli USA.</li>\n        <li>31 ott 2024: OpenAI lancia ChatGPT Search.</li>\n        <li>5 mar 2025: AIO su Gemini 2.0; AI Mode in Labs.</li>\n        <li>26 mar 2025: AI Overviews arrivano in Italia.</li>\n        <li>20 mag 2025: AI Mode esteso a tutti gli USA.</li>\n        <li>15 mag 2026: guida ufficiale Google sulla GEO.</li>\n        <li>5 giu 2026: Google nomina AEO/GEO come categoria di servizio SEO.</li>\n      </ul>\n      <h4>Il paper fondativo</h4>\n      <p><strong>Aggarwal et al.</strong> (IIT Delhi/Princeton/Allen AI), KDD 2024 (arXiv:2311.09735). Su <strong>GEO-bench</strong> (10.000 query) hanno testato 9 metodi. I migliori: Quotation Addition <strong>+41%</strong>, Statistics Addition +31%, Cite Sources +28%, Fluency Optimization +28%. Il <strong>keyword stuffing</strong> è l'unico che peggiora (−8%). Cite Sources ha alzato la visibilità del <strong>115%</strong> per i siti in quinta posizione: la GEO favorisce chi parte indietro. La combinazione Fluency + Statistics supera ogni metodo singolo di oltre il 5,5%. Validazione reale su Perplexity: fino al +37%.</p>\n      <h4>Il comportamento è cambiato</h4>\n      <ul>\n        <li><strong>SparkToro/Similarweb (2026):</strong> 68,01% ricerche Google USA senza click (+7,56 punti dal 2024).</li>\n        <li><strong>Ahrefs (dic 2025):</strong> un AIO correla con CTR medio −58% per la pagina top.</li>\n        <li><strong>Pew Research (lug 2025):</strong> su 68.879 ricerche reali, click su link tradizionale all'8% con AIO vs 15% senza; solo l'1% clicca una fonte citata; 26% delle sessioni con AIO termina del tutto. Google ha contestato la metodologia.</li>\n        <li><strong>Seer (set 2025, &gt;25M impression):</strong> CTR organico per query con AIO −61% (1,76% → 0,61%).</li>\n        <li><strong>Gartner (feb 2024):</strong> previsione −25% del volume di ricerca tradizionale entro il 2026 (previsione, non consuntivo).</li>\n        <li><strong>Publisher:</strong> Press Gazette/Chartbeat −33% traffico Google globale 2025 (−38% USA, −17% Europa); il danno scala con la dimensione del sito.</li>\n      </ul>\n    </div>\n  </div>\n</section>\n\n<!-- SEC 2 -->\n<section id=\"s2\">\n  <div class=\"sec-grid\">\n    <div class=\"sec-aside\"><span class=\"num\">02</span><span class=\"lbl\">Meccanica</span></div>\n    <div class=\"sec-body\">\n      <h2>Come funzionano i motori</h2>\n      <p>Tutti usano una forma di <strong>RAG (Retrieval-Augmented Generation)</strong>: recuperano contenuti freschi dal web e li usano per costruire la risposta. Tesi tecnica di fondo: <strong>la pagina non è più l'unità di competizione, lo è il chunk.</strong></p>\n\n      <h3>2-bis · Le tre famiglie di retrieval</h3>\n      <p><strong>Dense (bi-encoder):</strong> query e documento codificati separatamente in un vettore; veloce (ANN su vettori pre-calcolati) ma \"comprime tutto il significato in un vettore prima di qualsiasi confronto\" — un chunk con tre concetti produce un vettore \"medio\" ambiguo. <strong>Sparse (BM25, SPLADE):</strong> match lessicale esatto, imbattibile su nomi propri e codici. <strong>Late interaction (ColBERT):</strong> embedding a livello di token, calcolo MaxSim; più spiegabile ma costoso in storage (BEIR: ~20GB/1M doc vs 0,4GB BM25 e ~3GB dense; ColBERTv2 comprime molto via quantization). Gli approcci <strong>ibridi dense+sparse battono ogni metodo singolo</strong>.</p>\n\n      <!-- DEMO 1 -->\n      <div class=\"demo\" id=\"demo-ds\">\n        <div class=\"demo-head\"><span class=\"dot\"></span>Demo 01 · Dense vs Sparse<span class=\"tag\">simulazione didattica</span></div>\n        <div class=\"demo-body\">\n          <label for=\"ds-q\">Query di ricerca</label>\n          <input type=\"text\" id=\"ds-q\" value=\"iPhone 15 Pro 256GB\" autocomplete=\"off\">\n          <div class=\"chips\" id=\"ds-chips\">\n            <span class=\"chip\" data-q=\"iPhone 15 Pro 256GB\">codice prodotto</span>\n            <span class=\"chip\" data-q=\"migliore portatile leggero per studenti\">linguaggio naturale</span>\n            <span class=\"chip\" data-q=\"come ridurre il consumo della batteria\">domanda how-to</span>\n          </div>\n          <div class=\"ds-grid\">\n            <div class=\"ds-col dense\"><h5>Dense · semantico</h5><div class=\"ds-score\" id=\"ds-dense-score\">—</div><div class=\"ds-bar\"><span id=\"ds-dense-bar\"></span></div><div class=\"ds-note\" id=\"ds-dense-note\"></div></div>\n            <div class=\"ds-col sparse\"><h5>Sparse · lessicale</h5><div class=\"ds-score\" id=\"ds-sparse-score\">—</div><div class=\"ds-bar\"><span id=\"ds-sparse-bar\"></span></div><div class=\"ds-note\" id=\"ds-sparse-note\"></div></div>\n          </div>\n        </div>\n        <div class=\"demo-cap\">Euristica didattica (non un vero motore): mostra <em>perché</em> i due approcci eccellono su query diverse. Codici e nomi propri premiano lo sparse; le query concettuali premiano il dense. I motori reali li combinano.</div>\n      </div>\n\n      <h3>2-bis · Embeddings</h3>\n      <p>Tre implicazioni operative: (1) <strong>stesso modello obbligatorio</strong> per indice e query, altrimenti i vettori vivono in spazi non allineati — causa #1 di RAG rotti silenziosamente; (2) <strong>context rot</strong> — la ricerca Chroma (lug 2025, 18 modelli inclusi GPT-4.1/Claude 4/Gemini 2.5) mostra che il retrieval degrada all'aumentare della lunghezza del contesto, anche su task semplici; (3) un vettore medio non è un buon vettore.</p>\n\n      <h3>2-bis · Chunking</h3>\n      <p>Il senso comune dice \"il semantic chunking è il migliore\"; i benchmark dicono il contrario. <strong>Vecta Benchmark (feb 2026):</strong> recursive a 512 token primo (69%), semantic al 54% (frammenti da ~43 token). <strong>MDPI Bioengineering (nov 2025):</strong> nel dominio clinico adaptive 87% vs 13-50% del fixed (p=0,001). <strong>arXiv 2506.17277 (chimica):</strong> recursive fino al +45% domain-weighted. <strong>arXiv 2512.05411 (enterprise):</strong> su doc ben strutturati il naive batte semantic e recursive. <strong>arXiv 2506.06339 (arabo):</strong> sentence-aware il migliore, semantic peggiore. Non si conciliano — è il punto: <strong>nessuna strategia è universalmente ottimale</strong>. Default robusto: recursive a 400-512 token con 10-20% overlap. <strong>La struttura del contenuto è il chunking che puoi controllare.</strong></p>\n\n      <!-- DEMO 2 -->\n      <div class=\"demo\" id=\"demo-chunk\">\n        <div class=\"demo-head\"><span class=\"dot\"></span>Demo 02 · Strategie di chunking<span class=\"tag\">interattiva</span></div>\n        <div class=\"demo-body\">\n          <label for=\"chunk-in\">Testo da spezzare</label>\n          <input type=\"text\" id=\"chunk-in\" value=\"La GEO ottimizza per i motori generativi. Le statistiche aumentano le citazioni. Il keyword stuffing invece le riduce. La freschezza conta molto per Perplexity.\" autocomplete=\"off\">\n          <div class=\"chunk-controls\">\n            <button data-mode=\"fixed\">Fixed-size</button>\n            <button data-mode=\"recursive\">Recursive</button>\n            <button data-mode=\"semantic\">Semantic</button>\n          </div>\n          <div class=\"chunk-out\" id=\"chunk-out\"></div>\n          <div class=\"chunk-meta\" id=\"chunk-meta\"></div>\n        </div>\n        <div class=\"demo-cap\">Il fixed taglia a lunghezza fissa (rompe le frasi); il recursive rispetta i confini di frase; il semantic raggruppa per significato ma può frammentare troppo.</div>\n      </div>\n\n      <h3>2-bis · Re-ranking</h3>\n      <p>Retrieval a due stadi: <strong>recall</strong> (rete larga, 20-150 candidati via bi-encoder/BM25) e <strong>precision</strong> (un cross-encoder ri-valuta ogni coppia query-chunk <em>insieme</em>, tiene i top 3-8). Numeri: cross-encoder leggero ~50ms/20 doc, Cohere Rerank ~200ms, reranker LLM 1-3s; guadagno +5-15 punti nDCG@10. Il cross-encoder premia la <strong>rilevanza diretta e specifica</strong> — fondamento meccanico del perché l'answer-first funziona.</p>\n\n      <div class=\"panel\">\n        <h4>Dal meccanismo alla regola di markup</h4>\n        <div class=\"tablewrap\"><table>\n          <tr><th>Fatto meccanico</th><th>Regola per il contenuto</th></tr>\n          <tr><td>Dense comprime tutto in un vettore</td><td>Un'idea per sezione; non mescolare 3 temi</td></tr>\n          <tr><td>Sparse premia il match esatto</td><td>Includi termini/codici/nomi esatti</td></tr>\n          <tr><td>Ibrido batte i singoli metodi</td><td>Concetti chiari <em>e</em> terminologia precisa</td></tr>\n          <tr><td>Context rot</td><td>Risposta in alto, non a metà pagina</td></tr>\n          <tr><td>Heading chiari = confini netti</td><td><code>&lt;h2&gt;</code> a domanda + risposta sotto</td></tr>\n          <tr><td>Cross-encoder premia rilevanza diretta</td><td>Answer-first: risposta nei primi 40-60 token</td></tr>\n        </table></div>\n      </div>\n\n      <h3>2-ter · Reverse-engineering per-motore</h3>\n      <p class=\"note\">Distinzione epistemica: ciò che segue mescola <strong>fatti ufficiali</strong> (documentazione, API), <strong>analisi di reverse-engineering</strong> non confermate dai produttori e <strong>claim dei vendor</strong>. Lo segnalo caso per caso. Quest'area cambia a ogni aggiornamento di modello.</p>\n\n      <h4>ChatGPT — il tool web.run</h4>\n      <p>Studio RESONEO/Meteoria (Search Engine Land, mag 2026): tool interno <code>web.run</code> con <strong>12 operazioni</strong>, fan-out 2-10+ round, fan-out prodotto separato (<code>browse_rewritten_queries</code>: ricerca shopping per ogni singolo prodotto). Con lo switch a GPT-5.3 (4 mar 2026) i domini citati medi sono <strong>scesi da 19 a 15 (−20%)</strong> — \"Bigfoot Effect\": concentrazione su pochi domini autorevoli. È <code>ChatGPT-User</code> a fetchare le pagine durante la conversazione. Reddit è esente dai limiti copyright nel system prompt ricostruito. <em>(Reverse-engineering.)</em> Punto chiave: il modello formula query puntando a fonti che <strong>già conosce</strong> (visibilità parametrica) — un brand assente dalla memoria del modello non viene nemmeno considerato candidato.</p>\n\n      <h4>Gemini / AI Mode — fan-out documentato</h4>\n      <p>Qui c'è <strong>documentazione ufficiale</strong>: l'API di grounding restituisce <code>webSearchQueries</code> (le query realmente eseguite), <code>groundingChunks</code> (le fonti) e <code>groundingSupports</code> (mappatura frase→chunk, con startIndex/endIndex). Dal report Gemini 2.5: la ricerca è \"interlacciata col ragionamento\". A fine 2025 i modelli alimentano <strong>2 miliardi</strong> di utenti negli AI Overviews e <strong>750M</strong> nell'app Gemini. Ottimizzare per Gemini = coprire l'<strong>albero di sotto-domande</strong> di un tema.</p>\n\n      <!-- DEMO 3 -->\n      <div class=\"demo\" id=\"demo-fanout\">\n        <div class=\"demo-head\"><span class=\"dot\"></span>Demo 03 · Query fan-out<span class=\"tag\">interattiva</span></div>\n        <div class=\"demo-body\">\n          <label for=\"fo-q\">La tua domanda all'AI</label>\n          <input type=\"text\" id=\"fo-q\" value=\"qual è la migliore città dove trasferirsi per lavorare da remoto?\" autocomplete=\"off\">\n          <div style=\"margin-top:14px\"><button id=\"fo-go\">Esegui fan-out →</button> <button class=\"ghost\" id=\"fo-reset\">reset</button></div>\n          <div class=\"fan-out\" id=\"fo-out\"></div>\n        </div>\n        <div class=\"demo-cap\">Una domanda viene scomposta in più sotto-query parallele; ognuna recupera fonti diverse — per questo pagine non in top-10 vengono citate, se rispondono bene a una sotto-query.</div>\n      </div>\n\n      <h4>Perplexity / Sonar</h4>\n      <p>RAG con crawler proprio (PerplexityBot) + fetch realtime. Pipeline: query decomposition → retrieval → <strong>reranking a tre livelli</strong> (L3 favorirebbe earned media Tier-1 — analisi indipendente Yeşilyurt, ago 2025, non confermata) → sintesi con citazioni. <strong>Freschezza dominante:</strong> un contenuto \"aggiornato 2 ore fa\" è stato citato il +38% del gemello datato. ~780M query a maggio 2025 (+20% MoM, dichiarazione CEO).</p>\n\n      <h4>Claude — citazione a livello di frase</h4>\n      <p>Retrieval via provider esterno (overlap con Brave). La Citations API spezza i documenti in chunk a granularità di <strong>frase</strong>: l'output restituisce <code>cited_text</code>, <code>title</code>, <code>url</code>. Una frase ben costruita e autosufficiente è l'unità minima citabile. Tre bot: ClaudeBot (training), Claude-User (fetch), Claude-SearchBot (indicizzazione).</p>\n\n      <h4>Microsoft Copilot — GEO in policy</h4>\n      <p>Modello <strong>Prometheus</strong> su indice Bing; il \"Bing Orchestrator\" genera query interne iterative (fan-out). Le Webmaster Guidelines (riscrittura 27 feb 2026) trattano citazioni e grounding come <strong>esito di eleggibilità separato</strong> e introducono la GEO come categoria ufficiale: <code>NOARCHIVE</code> impedisce la citazione, <code>NOCACHE</code> la limita (sconsigliato), <code>data-snippet</code> la controlla a livello di paragrafo. Seer (feb 2025): l'87% delle citazioni SearchGPT coincide coi top result di Bing <em>(misurazione indipendente; il \"92% via Bing API\" è claim non confermato)</em>. IndexNow notifica Bing; Google non lo supporta.</p>\n\n      <div class=\"tablewrap\"><table>\n        <tr><th>Dimensione</th><th>ChatGPT</th><th>Gemini</th><th>Perplexity</th><th>Copilot</th><th>Claude</th></tr>\n        <tr><td>Indice/fonte</td><td>Scraping terzi (+tracce Google)</td><td>Indice Google + KG</td><td>Indice proprio + realtime</td><td>Bing/Prometheus</td><td>Esterno (overlap Brave)</td></tr>\n        <tr><td>Fan-out</td><td>Sì (web.run)</td><td>Sì (API)</td><td>Sì (decomposition)</td><td>Sì (Orchestrator)</td><td>Sì</td></tr>\n        <tr><td>Citazione</td><td>Inline variabile</td><td>frase→chunk</td><td>Inline, paragrafo</td><td>Numerata [1][2]</td><td>Inline, frase</td></tr>\n        <tr><td>Distintivo</td><td>Pochi domini autorevoli</td><td>Albero sotto-domande</td><td>Freshness + Tier-1</td><td>GEO in policy</td><td>Granularità di frase</td></tr>\n        <tr><td>Trasparenza</td><td>Bassa (rev-eng)</td><td>Media (API)</td><td>Bassa-media</td><td>Alta</td><td>Media (doc)</td></tr>\n      </table></div>\n    </div>\n  </div>\n</section>\n\n<!-- SEC 3 -->\n<section id=\"s3\">\n  <div class=\"sec-grid\">\n    <div class=\"sec-aside\"><span class=\"num\">03</span><span class=\"lbl\">Citabilità</span></div>\n    <div class=\"sec-body\">\n      <h2>Cosa rende un contenuto citabile</h2>\n      <h4>Tattiche con supporto empirico</h4>\n      <ul>\n        <li><strong>Statistiche e dati specifici</strong> (GEO paper: +31%).</li>\n        <li><strong>Citazioni e quotazioni di fonti</strong> (Quotation +41%, Cite Sources +28%).</li>\n        <li><strong>Freschezza</strong> (forte per Perplexity e query news/trend).</li>\n        <li><strong>Struttura answer-first</strong> (allineamento col cross-encoder).</li>\n        <li><strong>Autorevolezza/E-E-A-T</strong> e contenuto non-commodity con esperienza diretta (confermato da Google 2026).</li>\n        <li><strong>Menzioni del brand:</strong> studio Previsible (1,96M sessioni) → il volume di ricerca del brand è il predittore più forte delle citazioni AI (corr. 0,334), più dei backlink.</li>\n      </ul>\n      <p><strong>Correlazione col ranking tradizionale (dati contrastanti):</strong> Ahrefs trovava 76% di overlap tra citazioni AIO e top-10 a luglio 2025, solo 38% a gennaio 2026. Semrush: ~90% delle citazioni ChatGPT da URL fuori dalla top-20 Google. Il ranking aiuta ma non è condizione necessaria.</p>\n      <p><strong>robots.txt per crawler AI:</strong> \"bloccare tutti i bot AI\" è controproducente. Distinguere bot di <strong>training</strong> (GPTBot, ClaudeBot, Google-Extended) da bot di <strong>retrieval</strong> (OAI-SearchBot, ChatGPT-User, Claude-SearchBot, PerplexityBot): bloccare i secondi rimuove dal novero delle citazioni.</p>\n    </div>\n  </div>\n</section>\n\n<!-- SEC 4 mercato -->\n<section id=\"s4\">\n  <div class=\"sec-grid\">\n    <div class=\"sec-aside\"><span class=\"num\">04</span><span class=\"lbl\">Mercato IT/UE</span></div>\n    <div class=\"sec-body\">\n      <h2>Il mercato italiano ed europeo</h2>\n      <h4>Adozione</h4>\n      <p><strong>Eurostat 2025:</strong> uso GenAI in Italia al 20%, sotto la media UE del 33% e lontano da Norvegia (56%) e Danimarca (48%). ChatGPT in Europa: da 11,2 a 41,3M utenti mensili medi entro marzo 2025 (~+270%). L'Italia fu il primo paese al mondo a bloccare temporaneamente ChatGPT (marzo 2023).</p>\n      <h4>Tempistica AI Overviews</h4>\n      <p>In Italia dal <strong>26 marzo 2025</strong> (con Austria, Belgio, Germania, Irlanda, Polonia, Portogallo, Spagna, Svizzera), ~10 mesi dopo gli USA, su Gemini 2.0. L'AI Mode in italiano non risultava pienamente lanciato a metà 2026.</p>\n      <h4>Il panorama globale: i motori cinesi</h4>\n      <p>La frammentazione non è solo occidentale. <strong>Baidu ERNIE:</strong> ERNIE 4.5 open-source dal 30 giugno 2025 (licenza Apache 2.0); ERNIE Assistant a <strong>202M MAU</strong> (dic 2025); nel Q4 2025 i ricavi in abbonamento dell'infrastruttura AI accelerator sono cresciuti del <strong>+143% YoY</strong> (dal +128% del Q3), e il volume di chiamate dell'AI search API +110% QoQ (fonte: earnings call Baidu, 26 feb 2026). <strong>DeepSeek:</strong> modelli open-source cost-efficient; a metà 2025 una stima attribuiva ~34% della quota API developer a DeepSeek vs ~18% di ERNIE. <strong>Doubao (ByteDance):</strong> in testa a marzo 2026 con ~345M MAU (QuestMobile), davanti a Qwen (~166M) e DeepSeek (~127M); i principali player superano insieme i 900M di utenti.</p>\n      <p class=\"note\">Per un freelance italiano questi motori sono <strong>contesto</strong>, non azione quotidiana. Il punto è strutturale: la logica GEO (retrieval, grounding, citazioni, fan-out) è la stessa ovunque. I conteggi MAU cinesi divergono molto tra fonti: sono stime, sempre con fonte e data.</p>\n    </div>\n  </div>\n</section>\n\n<!-- SEC 4bis misurazione -->\n<section id=\"s4bis\">\n  <div class=\"sec-grid\">\n    <div class=\"sec-aside\"><span class=\"num\">04·B</span><span class=\"lbl\">Misurazione</span></div>\n    <div class=\"sec-body\">\n      <h2>Testare la GEO senza ingannarsi</h2>\n      <p>Tesi: <strong>la visibilità in AI search è una distribuzione, non un punteggio.</strong> Dal paper \"Don't Measure Once\" (Schulte et al., arXiv:2604.07585, Table 16): una run singola ha errore standard <strong>0,370</strong> (CI 95% ±0,724) — di fatto non informativa. A 7 run SE 0,081, a 8 run 0,062. L'overlap fonti tra due giorni consecutivi cade nel 34-42%.</p>\n\n      <!-- DEMO 4 -->\n      <div class=\"demo\" id=\"demo-se\">\n        <div class=\"demo-head\"><span class=\"dot\"></span>Demo 04 · Errore standard per numero di run<span class=\"tag\">dati reali · Schulte 2026</span></div>\n        <div class=\"demo-body\">\n          <label for=\"se-range\">Run ripetute per prompt: <strong id=\"se-n\">1</strong></label>\n          <input type=\"range\" id=\"se-range\" min=\"1\" max=\"9\" value=\"1\" step=\"1\">\n          <div class=\"se-readout\">\n            <div class=\"se-big\" id=\"se-val\">0,370<small>errore standard</small></div>\n            <div class=\"se-runs\" id=\"se-ci\">intervallo 95%: ±0,724</div>\n          </div>\n          <div class=\"se-track\"><div class=\"se-true\"></div><div class=\"se-ci\" id=\"se-band\"></div></div>\n          <div class=\"se-verdict bad\" id=\"se-verdict\"></div>\n        </div>\n        <div class=\"demo-cap\">Valori esatti dalla Table 16 (Appendice J) del paper. La barra rossa è l'intervallo di confidenza al 95% su un tasso reale del 50%: con 1 run può oscillare da −22% a +122%. Sposta il cursore.</div>\n      </div>\n\n      <h4>Citation drift</h4>\n      <p>Mensile 40-60%, semestrale 70-90% (Profound, su 240M citazioni); BrightEdge: 70× volatility gap; Reddit in ChatGPT da ~60% a ~10% in poche settimane (Semrush). Misurare con finestre, non snapshot.</p>\n      <h4>Protocollo minimo difendibile</h4>\n      <ol>\n        <li>20-30 prompt da buyer reale (non query vanity di brand).</li>\n        <li>Esegui su più motori — la visibilità in uno non predice gli altri.</li>\n        <li>7-10 run per prompt, distribuite su più giorni.</li>\n        <li>Logga: se sei apparso, quale fonte citata, quale competitor al tuo posto.</li>\n        <li>Intervalli bootstrap, reporting per-engine, gruppo di controllo (pagine non modificate) per separare l'effetto dal drift di sfondo.</li>\n      </ol>\n      <h4>Metriche che contano</h4>\n      <p>Citation Share per engine; Time-to-First-Citation (come distribuzione, non media); Inline Brand Hyperlink Share; Co-citation Rate; Citation Rank Stability. Da togliere se vendi software/servizi: lo Shopping Trigger Rate (il 79% dei prompt non triggera mai Shopping).</p>\n      <h4>Replicare il GEO paper</h4>\n      <p>Due varianti (baseline vs +statistiche/quotazioni), 30-50 query, 7-10 run per variante alternando l'ordine, misura il Position-Adjusted Word Count, confronto non parametrico (Mann-Whitney). Aspettativa calibrata: +20-40%, non \"10x\". Se vedi +300%, è rumore da campione piccolo.</p>\n      <p class=\"note\">Regola pratica: se un claim GEO non dichiara quante volte ha ripetuto ogni prompt e su quale periodo, è aneddoto. Con SE 0,370 a una run, qualsiasi cifra a due decimali senza run ripetute è statisticamente sospetta.</p>\n    </div>\n  </div>\n</section>\n\n<!-- SEC 4ter diritto -->\n<section id=\"s4ter\">\n  <div class=\"sec-grid\">\n    <div class=\"sec-aside\"><span class=\"num\">05</span><span class=\"lbl\">Diritto UE/IT</span></div>\n    <div class=\"sec-body\">\n      <h2>Il quadro che vincola la GEO in Europa</h2>\n      <h4>Eccezione TDM e opt-out (art. 4 CDSM)</h4>\n      <p>La <strong>Direttiva CDSM (UE) 2019/790</strong>: l'art. 3 copre il TDM scientifico, l'art. 4 quello commerciale — \"cornerstone of commercial AI training in the EU\". Il meccanismo chiave è l'<strong>opt-out (art. 4.3):</strong> il TDM è permesso di default <em>salvo</em> riserva espressa in modo \"leggibile meccanicamente\". L'<strong>AI Act</strong> (art. 53.1.c) obbliga i provider GPAI a rispettare queste riserve anche se addestrano fuori dall'UE (Considerando 106, \"Brussels effect\").</p>\n      <h4>Cosa rende valido un opt-out (nodo aperto)</h4>\n      <p><strong>Kneschke v. LAION</strong> (Amburgo 27 set 2024; appello OLG dic 2025): un opt-out in linguaggio naturale nei ToS <em>non</em> era valido perché non machine-readable. <strong>DPG Media v. HowardsHome</strong> (Amsterdam): serve una riserva \"rilevabile ed elaborabile da sistemi automatizzati\". Direzioni divergenti → non affidarsi solo a una clausola nei ToS: servono anche segnali tecnici (robots.txt, metadati).</p>\n      <h4>La spinta del Parlamento UE</h4>\n      <p>Procedura <strong>2025/2058(INI)</strong> \"Copyright and generative AI\" (relatore Voss): lo studio JURI <strong>PE 774095</strong> (Lucchi, 9 lug 2025) conclude che l'addestramento \"far exceeds the scope of the current TDM exceptions\"; il draft report <strong>PE775.433</strong> (27 giu 2025) chiede trasparenza e remunerazione. Risoluzione adottata il 10 marzo 2026 (T10-0066/2026). La maggioranza ritiene comunque non necessario un nuovo strumento \"at this stage\".</p>\n      <h4>Il caso italiano: FIEG vs Google</h4>\n      <p><strong>15 ott 2025:</strong> la FIEG deposita un reclamo all'AGCOM contro AI Overviews e AI Mode, \"traffic killer\", invocando il DSA. <strong>29 apr 2026:</strong> all'esito di audizioni (Google, FIEG, FISC), l'AGCOM decide di trasmettere il caso alla Commissione UE <strong>ex art. 65 DSA</strong> (artt. 27, 34, 35), con voto contrario della commissaria Giomi. È una segnalazione, non un procedimento sanzionatorio autonomo.</p>\n      <blockquote>L'opt-out protegge il copyright ma rimuove il contenuto dalle risposte generative, azzerando la visibilità GEO. Oggi le due cose sono in larga parte la stessa leva.</blockquote>\n      <p>Per un sito SME/e-commerce: di norma <strong>non</strong> fare opt-out dai bot di <em>retrieval</em> (vuoi essere citato); l'opt-out dai bot di <em>training</em> ha costo quasi nullo in visibilità. Bloccare GPTBot (training) non toglie da ChatGPT Search; bloccare OAI-SearchBot/ChatGPT-User sì.</p>\n      <h4>Garante Privacy</h4>\n      <p>Primo regolatore al mondo a limitare ChatGPT (31 mar 2023, Provv. 112/2023); riattivazione 28 apr 2023. Sanzione di <strong>15M€</strong> (Provv. 755), <strong>annullata dal Tribunale di Roma</strong> (sent. 4153/2026, depositata 18 mar 2026; motivazioni non ancora pubbliche a metà 2026).</p>\n      <h4>Timeline AI Act</h4>\n      <p>In vigore 1 ago 2024; obblighi GPAI dal 2 ago 2025; piena applicabilità (incl. etichettatura contenuti AI) dal 2 ago 2026.</p>\n    </div>\n  </div>\n</section>\n\n<!-- SEC 5 pratica -->\n<section id=\"s5\">\n  <div class=\"sec-grid\">\n    <div class=\"sec-aside\"><span class=\"num\">06</span><span class=\"lbl\">Pratica</span></div>\n    <div class=\"sec-body\">\n      <h2>Implicazioni operative</h2>\n      <h4>Cosa resta valido dalla SEO</h4>\n      <p>Crawlability e indicizzazione (estese a Bing per ChatGPT e ai bot di retrieval), autorevolezza/E-E-A-T, HTML semantico, rendering server-side (molti bot AI fetchano ma non eseguono JS).</p>\n      <h4>Cosa è nuovo</h4>\n      <p>Ottimizzazione a livello di chunk, ampiezza topica per il fan-out (pillar + cluster), costruzione di entità/brand, diversificazione delle superfici (YouTube, Reddit), indicizzazione su Bing.</p>\n      <h4>Tre fasi</h4>\n      <ol>\n        <li><strong>Fondamenta:</strong> verifica indicizzazione Bing (+IndexNow); audita robots.txt distinguendo training e retrieval; rendering server-side.</li>\n        <li><strong>Contenuto:</strong> pagine top in answer-first; statistiche citate e quotazioni; aggiornamento trimestrale; chunk autosufficienti (scrivendo bene, non spezzando artificialmente).</li>\n        <li><strong>Autorità e misurazione:</strong> menzioni di brand e citazioni di terze parti; tracking AI con run ripetute, non snapshot.</li>\n      </ol>\n      <h4>Soglie che cambiano le scelte</h4>\n      <ul>\n        <li>Se il traffico da AI search supera l'1-2% (oggi tipicamente &lt;1% ma converte meglio), aumenta l'investimento GEO.</li>\n        <li>Se l'overlap tra citazioni AI e ranking organico è basso, priorità a chunkability e autorevolezza.</li>\n        <li>Per l'Italia, monitora il lancio dell'AI Mode in italiano e l'evoluzione FIEG-AGCOM-UE.</li>\n      </ul>\n    </div>\n  </div>\n</section>\n\n<!-- SEC 6 antihype -->\n<section id=\"s6\">\n  <div class=\"sec-grid\">\n    <div class=\"sec-aside\"><span class=\"num\">07</span><span class=\"lbl\">Anti-hype</span></div>\n    <div class=\"sec-body\">\n      <h2>Cosa smontare nel discorso GEO</h2>\n      <p>Criterio unico: <strong>fonte primaria o esperimento replicabile vs ripetizione tra influencer.</strong></p>\n      <h4>Google smonta 5 miti (15 mag 2026)</h4>\n      <p>La guida ufficiale Search Central dichiara non necessari: <strong>llms.txt e markup speciali</strong>, il <strong>chunking manuale</strong> (i sistemi capiscono pagine multi-tema), le <strong>riscritture AI-specifiche</strong>, le <strong>menzioni inautentiche</strong> (spam), l'<strong>uso eccessivo di schema</strong>. Tesi: \"ottimizzare per l'AI generativa è ottimizzare per l'esperienza di ricerca, e quindi è ancora SEO\".</p>\n      <p>Il <strong>5 giugno 2026</strong> Google ha rincarato: ha pubblicato la guida sull'uso di <em>strumenti e servizi SEO di terze parti</em> e aggiornato \"Do you need an SEO?\", nominando esplicitamente <strong>AEO e GEO come categorie di servizio</strong>. Legittima la disciplina ma ne restringe il perimetro — resta \"ancora SEO\" — e invita alla cautela verso chi promette scorciatoie o garanzie di citazione nelle risposte AI.</p>\n      <div class=\"panel\">\n        <h4>La tensione onesta sul chunking</h4>\n        <p style=\"margin:0\">Google dice \"il chunking non serve\" — e ha ragione su un punto: non devi spezzare <em>fisicamente</em> la pagina né riscrivere in \"formato AI\". Ma \"non serve il chunking manuale\" ≠ \"la struttura non conta\": i chunk netti migliorano il retrieval a parità di tutto il resto, e li ottieni <strong>scrivendo bene</strong>. Inoltre la guida vale per <em>Google</em>; per ChatGPT, Perplexity e Claude (pipeline RAG proprie) la struttura resta più rilevante. Generalizzare \"il chunking è morto\" a tutti i motori è iper-estensione.</p>\n      </div>\n      <h4>llms.txt — il caso da manuale</h4>\n      <p>Google (Mueller, Illyes) dichiara di non usarlo. Otterly: 84 richieste su 62.100 in 90 giorni (0,1%); Ahrefs (mag 2026): il 97% dei file non riceve richieste; SE Ranking (~300k domini): nessuna correlazione con le citazioni. Wix stima ~120k file indicizzati (stima di parte, internamente incoerente col \"125k\" del sottotitolo). <strong>Verdetto:</strong> leva di citazione AI non provata, con evidenza contraria. Caso d'uso legittimo e ristretto (documentazione per dev tool).</p>\n      <h4>Servire le pagine in Markdown</h4>\n      <p>Domanda ricorrente: conviene pubblicare una versione Markdown delle pagine per farsi citare meglio? Per i motori mainstream è <strong>marginale/situazionale, non provato</strong>. Distinzione tecnica: la <strong>content negotiation</strong> via <code>Accept: text/markdown</code> sullo stesso URL è standard HTTP legittimo; i <strong>file <code>.md</code> a URL separati</strong> sono definiti da Google e Bing come potenziale cloaking e raddoppio del crawl budget. I crawler di ricerca (GPTBot, PerplexityBot, Googlebot, Bingbot) <em>non</em> negoziano Markdown — lo fanno solo alcuni agenti di coding (Claude Code, Cursor). Evidenza empirica: Profound (esperimento controllato, 381 pagine) trova ~16% di lift <em>non statisticamente significativo</em>; Otterly trova 0% di traffico e zero citazioni ai file <code>.md</code>. Il vantaggio reale del Markdown è la tokenizzazione (~80% di token in meno), ma beneficia chi <em>converte</em> l'HTML (Jina Reader, Firecrawl, le pipeline RAG lo fanno già). Google (15 mag 2026): <em>\"non serve creare file machine-readable, AI text files o Markdown\"</em>. <strong>Verdetto:</strong> utile solo per documentazione tecnica consultata da agenti in tempo reale; per un sito generico conta molto di più l'HTML semantico pulito. Se lo implementi, usa content negotiation con <code>Vary: Accept</code>, mai file <code>.md</code> indicizzabili separati.</p>\n      <h4>Schema/structured data</h4>\n      <p>Google (mag 2026) lo dichiara <strong>non richiesto</strong> per le risposte AI. Gli studi di correlazione sono confusi da variabili terze (i siti con schema sono anche più curati). Resta utile per i suoi scopi classici, non come \"trucco AI\".</p>\n      <h4>I numeri-civetta dei vendor</h4>\n      <p>\"data-rich citati 2,7x in più\", \"FCP &lt;0,4s = 6,7 citazioni\": spesso senza metodologia, campione, numero di run. Alla luce del SE 0,370 a una run, qualsiasi cifra a due decimali ottenuta senza run ripetute è sospetta.</p>\n      <h4>\"Il SEO è morto\"</h4>\n      <p>Iper-estensione opposta e altrettanto falsa: gli AIO girano <em>sopra</em> il ranking Search, la visibilità parametrica si costruisce coi segnali del SEO classico. <strong>La GEO è un'estensione del SEO, non un sostituto.</strong></p>\n      <div class=\"tablewrap\"><table>\n        <tr><th>Claim GEO</th><th>Verdetto</th><th>Priorità</th></tr>\n        <tr><td>Statistiche + citazioni di fonti</td><td><span class=\"badge b-ok\">Provato</span></td><td>Alta</td></tr>\n        <tr><td>Freschezza del contenuto</td><td><span class=\"badge b-ok\">Provato</span></td><td>Alta</td></tr>\n        <tr><td>Struttura answer-first</td><td><span class=\"badge b-ok\">Solido</span></td><td>Alta</td></tr>\n        <tr><td>Menzioni brand &gt; backlink</td><td><span class=\"badge b-warn\">1 studio</span></td><td>Media</td></tr>\n        <tr><td>Schema per citazione AI</td><td><span class=\"badge b-warn\">Sopravvalutato</span></td><td>Bassa</td></tr>\n        <tr><td>Chunking manuale</td><td><span class=\"badge b-bad\">Mito (Google)</span></td><td>Bassa</td></tr>\n        <tr><td>llms.txt come leva</td><td><span class=\"badge b-bad\">Non provato</span></td><td>Bassissima</td></tr>\n        <tr><td>Servire pagine in Markdown</td><td><span class=\"badge b-warn\">Marginale</span></td><td>Bassa</td></tr>\n        <tr><td>\"Il SEO è morto\"</td><td><span class=\"badge b-bad\">Falso</span></td><td>—</td></tr>\n      </table></div>\n    </div>\n  </div>\n</section>\n\n</div>\n</main>\n\n<footer>\n  <div class=\"wrap\">\n    <h2>Fonti principali</h2>\n    <div class=\"biblio\">\n      <h4>Paper e benchmark</h4>\n      <ul>\n        <li>Aggarwal P. et al., <em>GEO</em>, arXiv:2311.09735 (KDD 2024) — <a href=\"https://arxiv.org/abs/2311.09735\">arxiv.org/abs/2311.09735</a></li>\n        <li>Schulte J. et al., <em>Don't Measure Once</em>, arXiv:2604.07585 — <a href=\"https://arxiv.org/abs/2604.07585\">arxiv.org/abs/2604.07585</a></li>\n        <li>Vecta Benchmark (feb 2026); BEIR arXiv:2104.08663; Chroma <em>Context Rot</em> (lug 2025)</li>\n      </ul>\n      <h4>Comportamento di ricerca</h4>\n      <ul>\n        <li>SparkToro/Similarweb, <em>Zero-click 2026</em> — <a href=\"https://sparktoro.com/blog/in-2026-less-than-one-third-of-google-searches-still-send-a-click/\">sparktoro.com</a></li>\n        <li>Pew Research (lug 2025); Ahrefs <em>AI Overviews Reduce Clicks by 58%</em></li>\n      </ul>\n      <h4>Reverse-engineering</h4>\n      <ul>\n        <li>RESONEO/Meteoria, <em>Inside ChatGPT Search: web.run</em>, Search Engine Land (mag 2026) — <a href=\"https://searchengineland.com/inside-chatgpt-search-web-run-fan-out-queries-ai-visibility-477339\">searchengineland.com</a></li>\n        <li>Google, <em>Gemini API — Grounding</em> — <a href=\"https://ai.google.dev/gemini-api/docs/google-search\">ai.google.dev</a></li>\n        <li>Seer Interactive, <em>SearchGPT ↔ Bing 87%</em> (feb 2025); Anthropic <em>Web search docs</em>; Yeşilyurt (Perplexity, ago 2025)</li>\n      </ul>\n      <h4>Mercato cinese</h4>\n      <ul>\n        <li>Baidu, <em>Q4 & FY2025 Results</em> (26 feb 2026) — <a href=\"https://ir.baidu.com/news-releases/news-release-details/baidu-announces-fourth-quarter-and-fiscal-year-2025-results\">ir.baidu.com</a></li>\n        <li>QuestMobile via Caixin (Doubao ~345M MAU, mar 2026)</li>\n      </ul>\n      <h4>Diritto UE/Italia</h4>\n      <ul>\n        <li>Direttiva CDSM (UE) 2019/790; AI Act (Reg. UE 2024/1689); Parlamento UE 2025/2058(INI) — <a href=\"https://oeil.secure.europarl.europa.eu/oeil/en/procedure-file?reference=2025/2058(INI)\">oeil.europarl.europa.eu</a></li>\n        <li>Kneschke v. LAION (Amburgo/OLG); DPG Media v. HowardsHome (Amsterdam)</li>\n        <li>AGCOM, segnalazione ex art. 65 DSA (29 apr 2026); reclamo FIEG (15 ott 2025); Garante Provv. 112/2023 e 755; Trib. Roma 4153/2026</li>\n      </ul>\n      <h4>Anti-hype</h4>\n      <ul>\n        <li>Google Search Central, <em>Optimizing for generative AI features</em> (15 mag 2026) — <a href=\"https://developers.google.com/search/blog/2026/05/a-new-resource-for-optimizing\">developers.google.com</a>; <em>third-party SEO tools/services</em> e <em>Do you need an SEO?</em> (5 giu 2026, nomina AEO/GEO)</li>\n        <li>Ahrefs <em>97% of llms.txt files never get read</em> — <a href=\"https://ahrefs.com/blog/llmstxt-study/\">ahrefs.com</a>; SE Ranking; Otterly; Wix Studio</li>\n        <li>Markdown per le pagine — Profound <em>Markdown vs HTML experiment</em> — <a href=\"https://www.tryprofound.com/blog/does-markdown-increase-ai-bot-traffic\">tryprofound.com</a>; Otterly <em>md vs HTML</em>; Checkly <em>content negotiation</em>; Cloudflare <em>Markdown for Agents</em>; Google <em>AI optimization guide</em></li>\n      </ul>\n    </div>\n    <div class=\"foot-meta\">\n      White paper a cura di Federico Calicchia · redatto con il supporto di Claude Opus 4.8 (Anthropic). Ultimo aggiornamento: 16 giugno 2026.<br>\n      Le demo 01-03 sono simulazioni didattiche client-side (non motori reali); la demo 04 usa i dati esatti del paper Schulte et al. Statistiche e meccanismi hanno validità temporale limitata.\n    </div>\n  </div>\n</footer>",
  en: GEO_WP_BODY_EN,
};
